class Solution {
public:
    string removeOccurrences(string s, string part) {
        int n = s.length();
        int m = part.length();

        string result = "";
        for (int i = 0; i < n; i++) {
            while (i + m - 1 < n && s[i + m - 1] == part[m - 1]) {
                result += s.substr(i, m);
                i += m;
            }
        }
        return result;
    }
};
```

